import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Box, Activity, ShieldAlert, BarChart, crosshair } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    // --- STATE MANAGEMENT ---
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    // --- 1. DATA INITIALIZATION ---
    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) {
                    initializeStocks(res.data[0].holdings);
                }
            } catch (err) {
                console.error("VAULT_OFFLINE");
            }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            
            setStocks(tickers.map(t => ({
                ticker: t,
                price: Math.floor(Math.random() * 1500) + 400,
                change: 0.00
            })));
        } catch (e) { setStocks([]); }
    };

    // --- 2. LIVE PULSE LOGIC ---
    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 6;
                return {
                    ...s,
                    price: parseFloat((s.price + move).toFixed(2)),
                    change: parseFloat(move.toFixed(2))
                };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (direction) => {
        let newIndex = currentIndex + direction;
        if (newIndex >= 0 && newIndex < history.length) {
            setCurrentIndex(newIndex);
            initializeStocks(history[newIndex].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div className="reveal-node" style={containerStyle}>
            {/* ── Status Header ── */}
            <div style={statusHeader}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <Activity size={20} color={isConnected ? "#10b981" : "#ef4444"} />
                    <h2 style={titleStyle}>LIVE_TERMINAL_PULSE</h2>
                </div>
                <div style={connectionBadge(isConnected)}>
                    {isConnected ? 'UPLINK_STABLE' : 'LINK_INTERRUPTED'}
                </div>
            </div>

            {/* ── Navigation & Strategy Context ── */}
            <div style={navBar}>
                <button onClick={() => navigate(1)} disabled={currentIndex === history.length - 1} style={navBtn(currentIndex === history.length - 1)}>
                    <ChevronLeft size={20}/> PREV_NODE
                </button>
                <div style={nodeContext}>
                    <Box size={14} color="var(--accent-primary)" />
                    <div style={nodeMeta}>
                        <span style={nodeLabel}>STRATEGY_NODE_INDEX</span>
                        <span style={nodeGoal}>{activeNode ? activeNode.goal.substring(0, 45) : 'AWAITING_DATA...'}</span>
                    </div>
                </div>
                <button onClick={() => navigate(-1)} disabled={currentIndex === 0} style={navBtn(currentIndex === 0)}>
                    NEXT_NODE <ChevronRight size={20}/>
                </button>
            </div>

            {/* ── NEW: Advanced Analytics Row ── */}
            <div style={analyticsGrid}>
                {/* Risk Auditor */}
                <div style={moduleCard}>
                    <div style={moduleHeader}><BarChart size={12}/> RISK_AUDIT</div>
                    <div style={progressContainer}>
                        <div style={progressBar(activeNode?.risk_score || 50)} />
                    </div>
                    <span style={moduleValue}>{activeNode?.risk_score || 0}% EXPOSURE</span>
                </div>

                {/* Black Swan Resilience */}
                <div style={moduleCard}>
                    <div style={moduleHeader}><ShieldAlert size={12}/> SWAN_RESILIENCE</div>
                    <span style={moduleValue}>-12.45% <small style={{color:'var(--text-muted)'}}>EST_DRAWDOWN</small></span>
                    <div style={resilienceTag}>STRESS_TESTED</div>
                </div>

                {/* Signal Confidence */}
                <div style={moduleCard}>
                    <div style={moduleHeader}><Zap size={12}/> SIGNAL_STRENGTH</div>
                    <div style={{display:'flex', gap:'4px', marginTop:'8px'}}>
                        {[1,2,3,4,5].map(b => (
                            <div key={b} style={strengthBar(b <= 4)} />
                        ))}
                    </div>
                    <span style={moduleValue}>CONFIDENCE: HIGH</span>
                </div>
            </div>

            {/* ── Live Ticker Grid ── */}
            <div style={gridStyle}>
                {stocks.map((stock, i) => (
                    <div key={i} style={stockCard(stock.change >= 0)}>
                        <div style={cardHeader}>
                            <span style={tickerText}>{stock.ticker}</span>
                            <span style={statusMini}>REAL_TIME</span>
                        </div>
                        <div style={priceText}>₹{stock.price.toLocaleString()}</div>
                        <div style={changeRow(stock.change >= 0)}>
                            {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                            <span>{stock.change >= 0 ? '+' : ''}{stock.change}%</span>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

/* --- Terminal Styles (Emerald x Charcoal) --- */
